/// - `in_target` must be a valid pointer.
/// - `out_ref` must be a valid pointer.
#[cfg(feature = "CarbonEventsCore")]
#[inline]
pub unsafe fn RegisterEventHotKey(
    in_hot_key_code: u32,
    in_hot_key_modifiers: u32,
    in_hot_key_id: EventHotKeyID,
    in_target: EventTargetRef,
    in_options: OptionBits,
    out_ref: *mut EventHotKeyRef,
) -> OSStatus {
    extern "C-unwind" {
        fn RegisterEventHotKey(
            in_hot_key_code: u32,
            in_hot_key_modifiers: u32,
            in_hot_key_id: EventHotKeyID,
            in_target: EventTargetRef,
            in_options: OptionBits,
            out_ref: *mut EventHotKeyRef,
        ) -> OSStatus;
    }
    unsafe {
        RegisterEventHotKey(
            in_hot_key_code,
            in_hot_key_modifiers,
            in_hot_key_id,
            in_target,
            in_options,
            out_ref,
        )
    }
}

/// # Safety
///
/// `in_hot_key` must be a valid pointer.
#[inline]
pub unsafe fn UnregisterEventHotKey(in_hot_key: EventHotKeyRef) -> OSStatus {
    extern "C-unwind" {
        fn UnregisterEventHotKey(in_hot_key: EventHotKeyRef) -> OSStatus;
    }
    unsafe { UnregisterEventHotKey(in_hot_key) }
}

/// # Safety
///
/// `out_hot_key_array` might not allow `None`.
#[inline]
pub unsafe fn CopySymbolicHotKeys(
    out_hot_key_array: Option<&mut Option<CFRetained<CFArray>>>,
) -> OSStatus {
    extern "C-unwind" {
        fn CopySymbolicHotKeys(
            out_hot_key_array: Option<&mut Option<CFRetained<CFArray>>>,
        ) -> OSStatus;
    }
    if let Some(out_hot_key_array) = out_hot_key_array.as_ref() {
        assert!(
            out_hot_key_array.is_none(),
            "parameter `out_hot_key_array` must point to `None` on entry"
        );
    };
    unsafe { CopySymbolicHotKeys(out_hot_key_array) }
}

